previewCss:
.darma-loader-uiverse-orbital-status-dots {
  align-items: center;
  border: 16px solid rgba(119, 119, 119, 0.05);
  border-radius: 50%;
  box-shadow:
    0 0 5px #f1f1f1,
    0 0 5px #d1d1d1 inset;
  display: flex;
  height: 100px;
  justify-content: center;
  width: 100px;
}

.darma-loader-uiverse-orbital-status-dots > .darma-loader-uiverse-orbital-status-dots__text {
color: #888;
font-size: 10px;
font-weight: 200;
opacity: 0;
transition: all 200ms;
}

.darma-loader-uiverse-orbital-status-dots:hover > .darma-loader-uiverse-orbital-status-dots__text {
font-weight: 400;
opacity: 1;
}

.darma-loader-uiverse-orbital-status-dots__dot,
.darma-loader-uiverse-orbital-status-dots__shadow {
background-color: #ccc;
border-radius: 50%;
height: 16px;
margin: 40px;
position: absolute;
width: 16px;
}

.darma-loader-uiverse-orbital-status-dots__shadow:nth-child(1) {
animation: darma-loader-uiverse-orbital-status-dots-orbit 1s infinite 0.02s;
}

.darma-loader-uiverse-orbital-status-dots__shadow:nth-child(2) {
animation: darma-loader-uiverse-orbital-status-dots-orbit 1s infinite 0.04s;
}

.darma-loader-uiverse-orbital-status-dots__shadow:nth-child(3) {
animation: darma-loader-uiverse-orbital-status-dots-orbit 1s infinite 0.06s;
}

.darma-loader-uiverse-orbital-status-dots__dot {
animation: darma-loader-uiverse-orbital-status-dots-orbit 1s infinite;
background-color: #bbb;
border-radius: 50%;
height: 18px;
position: absolute;
width: 18px;
}

@keyframes darma-loader-uiverse-orbital-status-dots-orbit {
from {
transform: rotate(0deg) translateX(42px) rotate(0deg);
}
to {
transform: rotate(360deg) translateX(42px) rotate(-360deg);
}
}

